{"meta": null, "content": [{"type": "text", "text": "{"content":"501: \tfinishQueue, err := ng.queueActive(ctx, qry)\n502: \tif err != nil {\n503: \t\treturn nil, err\n504: \t}\n505: \tdefer finishQueue()\n506: \texpr, err := parser.ParseExpr(qs)\n507: \tif err != nil {\n508: \t\treturn nil, err\n509: \t}\n510: \tif err := ng.validateOpts(expr); err != nil {\n511: \t\treturn nil, err\n512: \t}\n513: \tif expr.Type() != parser.ValueTypeVector \u0026\u0026 expr.Type() != parser.ValueTypeScalar {\n514: \t\treturn nil, fmt.Errorf(\"invalid expression type %q for range query, must be Scalar or instant Vector\", parser.DocumentedType(expr.Type()))\n515: \t}\n516: \t*pExpr, err = PreprocessExpr(expr, start, end, interval)\n517: \n518: \treturn qry, err\n519: }\n520: \n521: func (ng *Engine) newQuery(q storage.Queryable, qs string, opts QueryOpts, start, end time.Time, interval time.Duration) (*parser.Expr, *query) {\n522: \tif opts == nil {\n523: \t\topts = NewPrometheusQueryOpts(false, 0)\n524: \t}\n525: \n526: \tlookbackDelta := opts.LookbackDelta()\n527: \tif lookbackDelta \u003c= 0 {\n528: \t\tlookbackDelta = ng.lookbackDelta\n529: \t}\n530: \n531: \tes := \u0026parser.EvalStmt{\n532: \t\tStart:         start,\n533: \t\tEnd:           end,\n534: \t\tInterval:      interval,\n535: \t\tLookbackDelta: lookbackDelta,\n536: \t}\n537: \tqry := \u0026query{\n538: \t\tq:           qs,\n539: \t\tstmt:        es,\n540: \t\tng:          ng,\n541: \t\tstats:       stats.NewQueryTimers(),\n542: \t\tsampleStats: stats.NewQuerySamples(ng.enablePerStepStats \u0026\u0026 opts.EnablePerStepStats()),\n543: \t\tqueryable:   q,\n544: \t}\n545: \treturn \u0026es.Expr, qry\n546: }\n547: \n548: var (\n549: \tErrValidationAtModifierDisabled     = errors.New(\"@ modifier is disabled\")\n550: \tErrValidationNegativeOffsetDisabled = errors.New(\"negative offset is disabled\")\n551: )\n552: \n553: func (ng *Engine) validateOpts(expr parser.Expr) error {\n554: \tif ng.enableAtModifier \u0026\u0026 ng.enableNegativeOffset {\n555: \t\treturn nil\n556: \t}\n557: \n558: \tvar atModifierUsed, negativeOffsetUsed bool\n559: \n560: \tvar validationErr error\n561: \tparser.Inspect(expr, func(node parser.Node, _ []parser.Node) error {\n562: \t\tswitch n := node.(type) {\n563: \t\tcase *parser.VectorSelector:\n564: \t\t\tif n.Timestamp != nil || n.StartOrEnd == parser.START || n.StartOrEnd == parser.END {\n565: \t\t\t\tatModifierUsed = true\n566: \t\t\t}\n567: \t\t\tif n.OriginalOffset \u003c 0 {\n568: \t\t\t\tnegativeOffsetUsed = true\n569: \t\t\t}\n570: \n571: \t\tcase *parser.MatrixSelector:\n572: \t\t\tvs := n.VectorSelector.(*parser.VectorSelector)\n573: \t\t\tif vs.Timestamp != nil || vs.StartOrEnd == parser.START || vs.StartOrEnd == parser.END {\n574: \t\t\t\tatModifierUsed = true\n575: \t\t\t}\n576: \t\t\tif vs.OriginalOffset \u003c 0 {\n577: \t\t\t\tnegativeOffsetUsed = true\n578: \t\t\t}\n579: \n580: \t\tcase *parser.SubqueryExpr:\n581: \t\t\tif n.Timestamp != nil || n.StartOrEnd == parser.START || n.StartOrEnd == parser.END {\n582: \t\t\t\tatModifierUsed = true\n583: \t\t\t}\n584: \t\t\tif n.OriginalOffset \u003c 0 {\n585: \t\t\t\tnegativeOffsetUsed = true\n586: \t\t\t}\n587: \t\t}\n588: \n589: \t\tif atModifierUsed \u0026\u0026 !ng.enableAtModifier {\n590: \t\t\tvalidationErr = ErrValidationAtModifierDisabled\n591: \t\t\treturn validationErr\n592: \t\t}\n593: \t\tif negativeOffsetUsed \u0026\u0026 !ng.enableNegativeOffset {\n594: \t\t\tvalidationErr = ErrValidationNegativeOffsetDisabled\n595: \t\t\treturn validationErr\n596: \t\t}\n597: \n598: \t\treturn nil\n599: \t})\n600: \n601: \treturn validationErr\n602: }\n603: \n604: // NewTestQuery injects special behaviour into Query for testing.\n605: func (ng *Engine) NewTestQuery(f func(context.Context) error) Query {\n606: \tqry := \u0026query{\n607: \t\tq:           \"test statement\",\n608: \t\tstmt:        parser.TestStmt(f),\n609: \t\tng:          ng,\n610: \t\tstats:       stats.NewQueryTimers(),\n611: \t\tsampleStats: stats.NewQuerySamples(ng.enablePerStepStats),\n612: \t}\n613: \treturn qry\n614: }\n615: \n616: // exec executes the query.\n617: //\n618: // At this point per query only one EvalStmt is evaluated. Alert and record\n619: // statements are not handled by the Engine.\n620: func (ng *Engine) exec(ctx context.Context, q *query) (v parser.Value, ws annotations.Annotations, err error) {\n621: \tng.metrics.currentQueries.Inc()\n622: \tdefer func() {\n623: \t\tng.metrics.currentQueries.Dec()\n624: \t\tng.metrics.querySamples.Add(float64(q.sampleStats.TotalSamples))\n625: \t}()\n626: \n627: \tctx, cancel := context.WithTimeout(ctx, ng.timeout)\n628: \tq.cancel = cancel\n629: \n630: \tdefer func() {\n631: \t\tng.queryLoggerLock.RLock()\n632: \t\tif l := ng.queryLogger; l != nil {\n633: \t\t\tlogger := slog.New(l)\n634: \t\t\tf := make([]slog.Attr, 0, 16) // Probably enough up front to not need to reallocate on append.\n635: \n636: \t\t\tparams := make(map[string]any, 4)\n637: \t\t\tparams[\"query\"] = q.q\n638: \t\t\tif eq, ok := q.Statement().(*parser.EvalStmt); ok {\n639: \t\t\t\tparams[\"start\"] = formatDate(eq.Start)\n640: \t\t\t\tparams[\"end\"] = formatDate(eq.End)\n641: \t\t\t\t// The step provided by the user is in seconds.\n642: \t\t\t\tparams[\"step\"] = int64(eq.Interval / (time.Second / time.Nanosecond))\n643: \t\t\t}\n644: \t\t\tf = append(f, slog.Any(\"params\", params))\n645: \t\t\tif err != nil {\n646: \t\t\t\tf = append(f, slog.Any(\"error\", err))\n647: \t\t\t}\n648: \t\t\tf = append(f, slog.Any(\"stats\", stats.NewQueryStats(q.Stats())))\n649: \t\t\tif span := trace.SpanFromContext(ctx); span != nil {\n650: \t\t\t\tf = append(f, slog.Any(\"spanID\", span.SpanContext().SpanID()))\n651: \t\t\t}\n652: \t\t\tif origin := ctx.Value(QueryOrigin{}); origin != nil {\n653: \t\t\t\tfor k, v := range origin.(map[string]any) {\n654: \t\t\t\t\tf = append(f, slog.Any(k, v))\n655: \t\t\t\t}\n656: \t\t\t}\n657: \t\t\tlogger.LogAttrs(context.Background(), slog.LevelInfo, \"promql query logged\", f...)\n658: \t\t\t// TODO: @tjhop -- do we still need this metric/error log if logger doesn't return errors?\n659: \t\t\t// ng.metrics.queryLogFailures.Inc()\n660: \t\t\t// ng.logger.Error(\"can't log query\", \"err\", err)\n661: \t\t}\n662: \t\tng.queryLoggerLock.RUnlock()\n663: \t}()\n664: \n665: \texecSpanTimer, ctx := q.stats.GetSpanTimer(ctx, stats.ExecTotalTime)\n666: \tdefer execSpanTimer.Finish()\n667: \n668: \tfinishQueue, err := ng.queueActive(ctx, q)\n669: \tif err != nil {\n670: \t\treturn nil, nil, err\n671: \t}\n672: \tdefer finishQueue()\n673: \n674: \t// Cancel when execution is done or an error was raised.\n675: \tdefer q.cancel()\n676: \n677: \tevalSpanTimer, ctx := q.stats.GetSpanTimer(ctx, stats.EvalTotalTime)\n678: \tdefer evalSpanTimer.Finish()\n679: \n680: \t// The base context might already be canceled on the first iteration (e.g. during shutdown).\n681: \tif err := contextDone(ctx, env); err != nil {\n682: \t\treturn nil, nil, err\n683: \t}\n684: \n685: \tswitch s := q.Statement().(type) {\n686: \tcase *parser.EvalStmt:\n687: \t\treturn ng.execEvalStmt(ctx, q, s)\n688: \tcase parser.TestStmt:\n689: \t\treturn nil, nil, s(ctx)\n690: \t}\n691: \n692: \tpanic(fmt.Errorf(\"promql.Engine.exec: unhandled statement of type %T\", q.Statement()))\n693: }\n694: \n695: // Log query in active log. The active log guarantees that we don't run over\n696: // MaxConcurrent queries.\n697: func (ng *Engine) queueActive(ctx context.Context, q *query) (func(), error) {\n698: \tif ng.activeQueryTracker == nil {\n699: \t\treturn func() {}, nil\n700: \t}\n701: \tqueueSpanTimer, _ := q.stats.GetSpanTimer(ctx, stats.ExecQueueTime, ng.metrics.queryQueueTime)\n702: \tqueryIndex, err := ng.activeQueryTracker.Insert(ctx, q.q)\n703: \tqueueSpanTimer.Finish()\n704: \treturn func() { ng.activeQueryTracker.Delete(queryIndex) }, err\n705: }\n706: \n707: func timeMilliseconds(t time.Time) int64 {\n708: \treturn t.UnixNano() / int64(time.Millisecond/time.Nanosecond)\n709: }\n710: \n711: func durationMilliseconds(d time.Duration) int64 {\n712: \treturn int64(d / (time.Millisecond / time.Nanosecond))\n713: }\n714: \n715: // execEvalStmt evaluates the expression of an evaluation statement for the given time range.\n716: func (ng *Engine) execEvalStmt(ctx context.Context, query *query, s *parser.EvalStmt) (parser.Value, annotations.Annotations, error) {\n717: \tprepareSpanTimer, ctxPrepare := query.stats.GetSpanTimer(ctx, stats.QueryPreparationTime, ng.metrics.queryPrepareTime)\n718: \tmint, maxt := FindMinMaxTime(s)\n719: \tquerier, err := query.queryable.Querier(mint, maxt)\n720: \tif err != nil {\n721: \t\tprepareSpanTimer.Finish()\n722: \t\treturn nil, nil, err\n723: \t}\n724: \tdefer querier.Close()\n725: \n726: \tng.populateSeries(ctxPrepare, querier, s)\n727: \tprepareSpanTimer.Finish()\n728: \n729: \t// Modify the offset of vector and matrix selectors for the @ modifier\n730: \t// w.r.t. the start time since only 1 evaluation will be done on them.\n731: \tsetOffsetForAtModifier(timeMilliseconds(s.Start), s.Expr)\n732: \tevalSpanTimer, ctxInnerEval := query.stats.GetSpanTimer(ctx, stats.InnerEvalTime, ng.metrics.queryInnerEval)\n733: \t// Instant evaluation. This is executed as a range evaluation with one step.\n734: \tif s.Start.Equal(s.End) \u0026\u0026 s.Interval == 0 {\n735: \t\tstart := timeMilliseconds(s.Start)\n736: \t\tevaluator := \u0026evaluator{\n737: \t\t\tstartTimestamp:           start,\n738: \t\t\tendTimestamp:             start,\n739: \t\t\tinterval:                 1,\n740: \t\t\tmaxSamples:               ng.maxSamplesPerQuery,\n741: \t\t\tlogger:                   ng.logger,\n742: \t\t\tlookbackDelta:            s.LookbackDelta,\n743: \t\t\tsamplesStats:             query.sampleStats,\n744: \t\t\tnoStepSubqueryIntervalFn: ng.noStepSubqueryIntervalFn,\n745: \t\t\tenableDelayedNameRemoval: ng.enableDelayedNameRemoval,\n746: \t\t\tenableTypeAndUnitLabels:  ng.enableTypeAndUnitLabels,